class Solution {
public:
    string gcdOfStrings(string str1, string str2) {
        string temp = str1 + str2;
        string gcd = str1;
        for (int i = 1; i <= str1.length(); i++) {
            if (temp.find(str1.substr(0, i)) == 0 && temp.length() % i == 0) {
                gcd = str1.substr(0, i);
            }
        }
        return gcd;
    }
};
